template = '''import os, glob, sys, re
sys.path.append(os.path.dirname(__file__))

DATA = %s


# Metadata fixes for files missing fields
METADATA_FIXES = {
}

BASE_DIR = r"F:\\My TW Coverage\\Pilot_Reports"

def update_file(filepath, ticker):
    if ticker not in DATA: return
    with open(filepath, 'r', encoding='utf-8') as f: content = f.read()
    new_data = DATA[ticker]

    if ticker in METADATA_FIXES:
        meta = METADATA_FIXES[ticker]
        if '**\u677f\u584a:**' not in content and '**\u5e02\u503c:**' not in content:
            content = content.replace(
                '## \u696d\u52d9\u7c21\u4ecb\\n',
                '## \u696d\u52d9\u7c21\u4ecb\\n**\u677f\u584a:** {sector}\\n**\u7522\u696d:** {industry}\\n**\u5e02\u503c:** N/A \u767e\u842c\u53f0\u5e63\\n**\u4f01\u696d\u50f9\u503c:** N/A \u767e\u842c\u53f0\u5e63\\n\\n'.format(**meta)
            )

    def repl_desc(m): return f"{m.group(1)}{new_data['desc']}\\n"
    content = re.sub(r'(## \u696d\u52d9\u7c21\u4ecb\\n(?:.*?\u4f01\u696d\u50f9\u503c:.*?\\n\\n|))(.*?)(?=\\n## \u4f9b\u61c9\u93c8\u4f4d\u7f6e)', repl_desc, content, flags=re.DOTALL)
    sc = new_data.get('supply_chain', f"*   **\u4e0a\u6e38**: {new_data.get('up','')}\\n*   **\u4e2d\u6e38**: {new_data.get('mid','')}\\n*   **\u4e0b\u6e38**: {new_data.get('down','')}\\n")
    if 'supply_chain' in new_data: sc = new_data['supply_chain'] + "\\n"
    content = re.sub(r'(## \u4f9b\u61c9\u93c8\u4f4d\u7f6e\\n)(.*?)(?=\\n## \u4e3b\u8981\u5ba2\u6236\u53ca\u4f9b\u61c9\u5546)', rf'\\g<1>{sc}', content, flags=re.DOTALL)
    ct = new_data['cust'] + "\\n" if 'supp' not in new_data else f"### \u4e3b\u8981\u5ba2\u6236\\n*   {new_data['cust']}\\n\\n### \u4e3b\u8981\u4f9b\u61c9\u5546\\n*   {new_data['supp']}\\n"
    content = re.sub(r'(## \u4e3b\u8981\u5ba2\u6236\u53ca\u4f9b\u61c9\u5546\\n)(.*?)(?=\\n## \u8ca1\u52d9\u6982\u6cc1)', rf'\\g<1>{ct}', content, flags=re.DOTALL)
    with open(filepath, 'w', encoding='utf-8') as f: f.write(content)
    try:
        print(f"Enriched: {os.path.basename(filepath)}")
    except UnicodeEncodeError:
        print(f"Enriched: ticker {ticker}")

def main():
    import sys
    if sys.platform == 'win32':
        sys.stdout.reconfigure(encoding='utf-8', errors='replace')
    for fp in glob.glob(os.path.join(BASE_DIR, "**", "*.md"), recursive=True):
        fn = os.path.basename(fp)
        m = re.search(r'^(\\d{4})_', fn)
        if m and m.group(1) in DATA: update_file(fp, m.group(1))

if __name__ == "__main__": main()
'''

data_str = pprint.pformat(DATA, width=300)
output = template % data_str

target = os.path.join(os.path.dirname(__file__), 'fix_batch.py')
with open(target, 'w', encoding='utf-8') as f:
    f.write(output)

print(f"Written {len(output)} bytes to {target}")
print(f"DATA keys: {list(DATA.keys())}")
